1	export type Customer = {
2	  yearsWithMHPCO: number;
3	};
4	
5	export type Item = {
6	  type: string;
7	  cursed?: boolean;
8	  enchantment?: number;
9	};
10	
11	export type QuoteStep = {
12	  op: "quote";
13	  items: Item[];
14	};
15	
16	export type Step = QuoteStep;
17	
18	export type Scenario = {
19	  customer: Customer;
20	  steps: Step[];
21	};
22	
23	export type QuoteResult = {
24	  premium: number;
25	};
26	
27	export type Result = QuoteResult;
28	
29	const PROCESSING_FEE = 5;
30	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
31	const CURSE_SURCHARGE_RATE = 0.5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const HIGH_ENCHANTMENT_MINIMUM = 5;
34	const LOYALTY_DISCOUNT_RATE = 0.2;
35	const LOYALTY_MINIMUM_YEARS = 2;
36	
37	const BASE_PREMIUMS: Record<string, number> = {
38	  sword: 100,
39	  amulet: 60,
40	  staff: 80,
41	  potion: 40,
42	  rune: 25,
43	  moonstone: 25,
44	};
45	
46	const COMPONENT_BLOCK_SIZE = 3;
47	const COMPONENT_BLOCK_PREMIUM = 60;
48	
49	const countByType = (items: Item[]): Map<string, number> => {
50	  const counts = new Map<string, number>();
51	  for (const item of items) {
52	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
53	  }
54	  return counts;
55	};
56	
57	const groupBasePremium = (type: string, count: number): number =>
58	  count === COMPONENT_BLOCK_SIZE
59	    ? COMPONENT_BLOCK_PREMIUM
60	    : count * BASE_PREMIUMS[type];
61	
62	const computeBasePremium = (items: Item[]): number =>
63	  [...countByType(items)].reduce(
64	    (total, [type, count]) => total + groupBasePremium(type, count),
65	    0,
66	  );
67	
68	const sumBy = (items: Item[], amount: (item: Item) => number): number =>
69	  items.reduce((total, item) => total + amount(item), 0);
70	
71	const itemCurseSurcharge = (item: Item): number =>
72	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
73	
74	const itemHighEnchantmentSurcharge = (item: Item): number =>
75	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_MINIMUM
76	    ? BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
77	    : 0;
78	
79	const computeLoyaltyDiscount = (
80	  customer: Customer,
81	  basePremium: number,
82	): number =>
83	  customer.yearsWithMHPCO >= LOYALTY_MINIMUM_YEARS
84	    ? basePremium * LOYALTY_DISCOUNT_RATE
85	    : 0;
86	
87	const quotePremium = (customer: Customer, items: Item[]): number => {
88	  const basePremium = computeBasePremium(items);
89	  const curseSurcharge = sumBy(items, itemCurseSurcharge);
90	  const highEnchantmentSurcharge = sumBy(items, itemHighEnchantmentSurcharge);
91	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
92	  const loyaltyDiscount = computeLoyaltyDiscount(customer, basePremium);
93	  const exactPremium =
94	    basePremium +
95	    curseSurcharge +
96	    highEnchantmentSurcharge +
97	    firstInsuranceSurcharge -
98	    loyaltyDiscount +
99	    PROCESSING_FEE;
100	  return Math.ceil(exactPremium);
101	};
102	
103	export const processScenario = (scenario: Scenario): { results: Result[] } => {
104	  return {
105	    results: [
106	      { premium: quotePremium(scenario.customer, scenario.steps[0].items) },
107	    ],
108	  };
109	};
